import sys
from html.parser import HTMLParser

class FormParser\(HTMLParser\):
    def __init__\(self\):
        super\(\).__init__\(\)
        self.inputs = {}
        self.selects = {}
        self.current_select = None
        self.selected_option = None
        self.options = []

    def handle_starttag\(self, tag, attrs\):
        attrs = dict\(attrs\)
        if tag == 'input':
            name = attrs.get\('name', ''\)
            value = attrs.get\('value', ''\)
            if name:
                self.inputs[name] = value
        elif tag == 'select':
            self.current_select = attrs.get\('name', ''\)
            self.selected_option = None
            self.options = []
        elif tag == 'option' and self.current_select:
            val = attrs.get\('value', ''\)
            selected = 'selected' in attrs
            self.options.append\(\(val, selected\)\)

    def handle_endtag\(self, tag\):
        if tag == 'select' and self.current_select:
            for val, selected in self.options:
                if selected:
                    self.selects[self.current_select] = val
                    break
            else:
                if self.options:
                    self.selects[self.current_select] = self.options[0][0]
            self.current_select = None

html = sys.stdin.read\(\)
parser = FormParser\(\)
parser.feed\(html\)
print\('=== Form inputs ==='\)
for k, v in parser.inputs.items\(\):
    print\(f'  {k} = {repr\(v\)}'\)
print\(\)
print\('=== Select defaults ==='\)
for k, v in parser.selects.items\(\):
    print\(f'  {k} = {repr\(v\)}'\)
")
